}

// NewTransportBuilder создает новый инстанс TransportBuilder
func NewTransportBuilder() *TransportBuilder {
    return &TransportBuilder{
        headers: http.Header{},
    }
}

// WithProxy настраивает прокси с необязательным именем пользователя и паролем
func (tb *TransportBuilder) WithProxy(proxyURL string, username, password string) *TransportBuilder {
    u, err := url.Parse(proxyURL)
    if err != nil {
