    }
    tb.proxyURL = u
    tb.proxyUsername = username
    tb.proxyPassword = password
    return tb
}

// WithoutProxy отключает прокси, включая системные прокси
func (tb *TransportBuilder) WithoutProxy() *TransportBuilder {
    tb.proxyURL = nil
    tb.proxyUsername = ""
    tb.proxyPassword = ""
    return tb
}

// WithClientAuth устанавливает учетные данные для аутентификации клиента в Elasticsearch
func (tb *TransportBuilder) WithClientAuth(username, password string) *TransportBuilder {
    tb.clientUsername = username
    tb.clientPassword = password
    return tb
}

// WithCert устанавливает сертификат для HTTPS-соединения
func (tb *TransportBuilder) WithCert(cert string) *TransportBuilder {
    tb.cert = cert
    return tb
}

// WithHeaders добавляет HTTP-заголовки, которые будут добавлены ко всем API-запросам клиента
func (tb *TransportBuilder) WithHeaders(headers http.Header) *TransportBuilder {
    tb.headers = headers
    return tb
}

// WithTimeout устанавливает глобальный тайм-аут для клиента
func (tb *TransportBuilder) WithTimeout(timeout time.Duration) *TransportBuilder {
    tb.timeout = timeout
    return tb
}

// build создает HTTP-транспорт для отправки API-запросов в Elasticsearch
func (tb *TransportBuilder) build() (*http.Client, error) {
    tr := &http.Transport{}

    if tb.proxyURL != nil {
        tr.Proxy = http.ProxyURL(tb.proxyURL)
        if tb.proxyUsername != "" && tb.proxyPassword != "" {
            basicAuth := fmt.Sprintf("%s:%s", tb.proxyUsername, tb.proxyPassword)
            basicAuthEncoded := "Basic " + base64.StdEncoding.EncodeToString([]byte(basicAuth))
            tr.ProxyConnectHeader = http.Header{"Proxy-Authorization": {basicAuthEncoded}}
        }
    } else {
        tr.Proxy = http.ProxyFromEnvironment // отключаем системные прокси
    }

    if tb.cert != "" {
        // Здесь можно добавить логику для загрузки и использования сертификата
        // Например, использовать tls.Config для настройки TLS
    }

    client := &http.Client{
        Transport: tr,
        Timeout:   tb.timeout,
    }

    // Добавляем учетные данные для аутентификации в Elasticsearch
    if tb.clientUsername != "" && tb.clientPassword != "" {
        basicAuth := fmt.Sprintf("%s:%s", tb.clientUsername, tb.clientPassword)
        basicAuthEncoded := "Basic " + base64.StdEncoding.EncodeToString([]byte(basicAuth))
        client.DefaultHeader().Add("Authorization", basicAuthEncoded)
    }

    // Добавляем пользовательские заголовки
    for key, values := range tb.headers {
        for _, value := range values {
            client.DefaultHeader().Add(key, value)
        }
    }

    return client, nil
}
```

**Примечания:**
