### Шаг 2: Функция ядра CUDA C++

Функция ядра будет вычислять новое состояние каждой клетки на основе количества живых соседей.

```cpp
__global__ void gameOfLifeKernel(CellState* grid, CellState* newGrid, int width, int height) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;

    if (x < width && y < height) {
        int liveNeighbors = 0;

        // Подсчёт живых соседей
        for (int i = -1; i <= 1; ++i) {
            for (int j = -1; j <= 1; ++j) {
                if (i == 0 && j == 0) continue; // Пропускаем саму клетку
                int nx = x + i;
                int ny = y + j;
                if (nx >= 0 && nx < width && ny >= 0 && ny < height) {
                    liveNeighbors += grid[ny * width + nx];
                }
            }
        }

        // Применение правил Игры Жизни
        CellState currentState = grid[y * width + x];
        if (currentState == 1 && (liveNeighbors < 2 || liveNeighbors > 3)) {
            newGrid[y * width + x] = 0; // Смерть от одиночества или перенаселения
        } else if (currentState == 0 && liveNeighbors == 3) {
            newGrid[y * width + x] = 1; // Рождение
        } else {
            newGrid[y * width + x] = currentState; // Сохранение текущего состояния
        }
    }
}
```

### Шаг 3: Вспомогательные функции

Необходимо реализовать функции для копирования данных между хостом и устройством, а также для управления несколькими GPU.

```cpp
void copyGridToDevice(CellState* hostGrid, CellState* deviceGrid, int size) {
    cudaMemcpy(deviceGrid, hostGrid, size, cudaMemcpyHostToDevice);
}

void copyGridFromDevice(CellState* deviceGrid, CellState* hostGrid, int size) {
    cudaMemcpy(hostGrid, deviceGrid, size, cudaMemcpyDeviceToHost);
}

void launchKernelOnGPU(int gpuId, CellState* grid, CellState* newGrid, int width, int height) {
    cudaSetDevice(gpuId);

    dim3 blockSize(16, 16);
    dim3 gridSize((width + blockSize.x - 1) / blockSize.x, (height + blockSize.y - 1) / blockSize.y);

    gameOfLifeKernel<<<gridSize, blockSize>>>(grid, newGrid, width, height);
    cudaDeviceSynchronize();
}
```

### Шаг 4: Управление несколькими GPU

Для управления несколькими GPU можно использовать цикл, который будет запускать ядро на каждом доступном устройстве.

```cpp
void runGameOfLifeOnMultipleGPUs(CellState* hostGrid, CellState* hostNewGrid, int width, int height, int numGPUs) {
    size_t gridSize = width * height * sizeof(CellState);
    CellState** deviceGrids = new CellState*[numGPUs];
    CellState** deviceNewGrids = new CellState*[numGPUs];

    for (int i = 0; i < numGPUs; ++i) {
        cudaSetDevice(i);
        cudaMalloc(&deviceGrids[i], gridSize);
        cudaMalloc(&deviceNewGrids[i], gridSize);
        copyGridToDevice(hostGrid, deviceGrids[i], gridSize);
    }

    for (int step = 0; step < NUM_STEPS; ++step) {
        for (int i = 0; i < numGPUs; ++i) {
            launchKernelOnGPU(i, deviceGrids[i], deviceNewGrids[i], width, height);
        }

        // Обмен данными между GPU (если необходимо)
        // ...

        // Копирование данных обратно на хост
        for (int i = 0; i < numGPUs; ++i) {
            copyGridFromDevice(deviceNewGrids[i], hostGrid, gridSize);
        }
    }

    for (int i = 0; i < numGPUs; ++i) {
        cudaFree(deviceGrids[i]);
        cudaFree(deviceNewGrids[i]);
    }

    delete[] deviceGrids;
    delete[] deviceNewGrids;
}
```

